package org.example.userservice.exceptions;

import jakarta.validation.ConstraintViolationException;
import org.example.userservice.dto.ApiResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.HttpStatusCode;
import org.springframework.http.ResponseEntity;
import org.springframework.http.converter.HttpMessageNotReadableException;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.security.core.AuthenticationException;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;
import org.springframework.web.context.request.WebRequest;
import org.springframework.web.servlet.mvc.method.annotation.ResponseEntityExceptionHandler;

import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;
import java.util.stream.Collectors;

@RestControllerAdvice
public class GlobalExceptionHandler extends ResponseEntityExceptionHandler {

    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    // Handle your own custom exception which carries an HttpStatus
    @ExceptionHandler(CustomException.class)
    public ResponseEntity<ApiResponse<?>> handleCustomException(CustomException ex) {
        HttpStatus status = ex.getStatus();
        if (status.is5xxServerError()) {
            // log stack trace for server errors
            log.error("CustomException -> {}", ex.getMessage(), ex);
        } else {
            log.warn("CustomException -> {}", ex.getMessage());
        }
        return ResponseEntity.status(status).body(ApiResponse.error(ex.getMessage()));
    }

    @ExceptionHandler(DataIntegrityViolationException.class)
    public ResponseEntity<ApiResponse<?>> handleDataIntegrityViolationException(DataIntegrityViolationException ex) {
        log.warn("Data integrity violation: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.CONFLICT).body(ApiResponse.error(ex.getMessage()));
    }

    // Handle validation errors from @Valid (request body) - Override without @ExceptionHandler
    @Override
    protected ResponseEntity<Object> handleMethodArgumentNotValid(
            MethodArgumentNotValidException ex, HttpHeaders headers, HttpStatusCode status, WebRequest request) {
        Map<String, List<String>> fieldErrors = ex.getBindingResult().getFieldErrors().stream()
                .collect(Collectors.groupingBy(
                        org.springframework.validation.FieldError::getField,
                        Collectors.mapping(org.springframework.validation.FieldError::getDefaultMessage, Collectors.toList())
                ));
        log.info("Validation errors: {}", fieldErrors);
        return ResponseEntity.status(status).body(ApiResponse.error("Validation failed", new HashMap<>(fieldErrors)));
    }

    // Handle JSON parse / bad request bodies - Override without @ExceptionHandler
    @Override
    protected ResponseEntity<Object> handleHttpMessageNotReadable(
            HttpMessageNotReadableException ex, HttpHeaders headers,
            HttpStatusCode status, WebRequest request) {

        log.info("Malformed JSON request: {}", ex.getMessage());
        return ResponseEntity.status(status).body(ApiResponse.error("Malformed request body"));
    }

    // Constraint violations (e.g. @Validated on method params)
    @ExceptionHandler(ConstraintViolationException.class)
    public ResponseEntity<ApiResponse<?>> handleConstraintViolation(ConstraintViolationException ex) {
        String msg = ex.getConstraintViolations().stream()
                .findFirst()
                .map(cv -> cv.getMessage() != null ? cv.getMessage() : "Request parameter invalid")
                .orElse("Constraint violation");
        log.info("Constraint violation: {}", msg);
        return ResponseEntity.badRequest().body(ApiResponse.error(msg));
    }

    // Security: authentication failure (401)
    @ExceptionHandler(AuthenticationException.class)
    public ResponseEntity<ApiResponse<?>> handleAuthenticationException(AuthenticationException ex) {
        log.info("Authentication failed: {}", ex.getMessage());
        HttpHeaders headers = new HttpHeaders();
        headers.add(HttpHeaders.WWW_AUTHENTICATE, "Bearer");
        return ResponseEntity.status(HttpStatus.UNAUTHORIZED).headers(headers).body(ApiResponse.error("Unauthorized"));
    }

    // Security: access denied (403)
    @ExceptionHandler(AccessDeniedException.class)
    public ResponseEntity<ApiResponse<?>> handleAccessDenied(AccessDeniedException ex) {
        log.warn("Access denied: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.FORBIDDEN).body(ApiResponse.error("Access denied"));
    }

    // Not found translations (NoSuchElementException often used)
    @ExceptionHandler(NoSuchElementException.class)
    public ResponseEntity<ApiResponse<?>> handleNotFound(NoSuchElementException ex) {
        log.info("Not found: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(ApiResponse.error("Resource not found"));
    }

    // Generic IllegalArgument -> 400
    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<ApiResponse<?>> handleIllegalArgument(IllegalArgumentException ex) {
        log.info("Bad request: {}", ex.getMessage());
        return ResponseEntity.badRequest().body(ApiResponse.error(ex.getMessage()));
    }

    // Fallback - don't leak internals; return safe generic error
    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiResponse<?>> handleAll(Exception ex) {
        // log stack trace on server side for diagnostics
        log.error("Unhandled exception: {}", ex.getMessage(), ex);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(ApiResponse.error("Internal server error"));
    }

}

package org.example.userservice.exceptions;

import jakarta.validation.ConstraintViolationException;
import org.example.userservice.dto.ApiResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.HttpStatusCode;
import org.springframework.http.ResponseEntity;
import org.springframework.http.converter.HttpMessageNotReadableException;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.security.core.AuthenticationException;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;
import org.springframework.web.context.request.WebRequest;
import org.springframework.web.servlet.mvc.method.annotation.ResponseEntityExceptionHandler;

import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;
import java.util.stream.Collectors;

@RestControllerAdvice
public class GlobalExceptionHandler extends ResponseEntityExceptionHandler {

    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    // Handle your own custom exception which carries an HttpStatus
    @ExceptionHandler(CustomException.class)
    public ResponseEntity<ApiResponse<?>> handleCustomException(CustomException ex) {
        HttpStatus status = ex.getStatus();
        if (status.is5xxServerError()) {
            // log stack trace for server errors
            log.error("CustomException -> {}", ex.getMessage(), ex);
        } else {
            log.warn("CustomException -> {}", ex.getMessage());
        }
        return ResponseEntity.status(status).body(ApiResponse.error(ex.getMessage()));
    }

    @ExceptionHandler(DataIntegrityViolationException.class)
    public ResponseEntity<ApiResponse<?>> handleDataIntegrityViolationException(DataIntegrityViolationException ex) {
        String message = ex.getMessage();
        HttpStatus status = HttpStatus.CONFLICT; // default for constraints

        // Email validation errors → 422 UNPROCESSABLE_ENTITY
        if (message != null && message.contains("Email")) {
            status = HttpStatus.UNPROCESSABLE_ENTITY;
        }

        log.warn("Data integrity violation: {}", message);
        return ResponseEntity.status(status).body(ApiResponse.error(message));
    }

    // Handle validation errors from @Valid (request body) - Override without @ExceptionHandler
    @Override
    protected ResponseEntity<Object> handleMethodArgumentNotValid(
            MethodArgumentNotValidException ex, HttpHeaders headers, HttpStatusCode status, WebRequest request) {
        Map<String, List<String>> fieldErrors = ex.getBindingResult().getFieldErrors().stream()
                .collect(Collectors.groupingBy(
                        org.springframework.validation.FieldError::getField,
                        Collectors.mapping(org.springframework.validation.FieldError::getDefaultMessage, Collectors.toList())
                ));
        log.info("Validation errors: {}", fieldErrors);
        return ResponseEntity.status(status).body(ApiResponse.error("Validation failed", new HashMap<>(fieldErrors)));
    }

    // Handle JSON parse / bad request bodies - Override without @ExceptionHandler
    @Override
    protected ResponseEntity<Object> handleHttpMessageNotReadable(
            HttpMessageNotReadableException ex, HttpHeaders headers,
            HttpStatusCode status, WebRequest request) {

        log.info("Malformed JSON request: {}", ex.getMessage());
        return ResponseEntity.status(status).body(ApiResponse.error("Malformed request body"));
    }

    // Constraint violations (e.g. @Validated on method params)
    @ExceptionHandler(ConstraintViolationException.class)
    public ResponseEntity<ApiResponse<?>> handleConstraintViolation(ConstraintViolationException ex) {
        String msg = ex.getConstraintViolations().stream()
                .findFirst()
                .map(cv -> cv.getMessage() != null ? cv.getMessage() : "Request parameter invalid")
                .orElse("Constraint violation");
        log.info("Constraint violation: {}", msg);
        return ResponseEntity.badRequest().body(ApiResponse.error(msg));
    }

    // Security: authentication failure (401)
    @ExceptionHandler(AuthenticationException.class)
    public ResponseEntity<ApiResponse<?>> handleAuthenticationException(AuthenticationException ex) {
        log.info("Authentication failed: {}", ex.getMessage());
        HttpHeaders headers = new HttpHeaders();
        headers.add(HttpHeaders.WWW_AUTHENTICATE, "Bearer");
        return ResponseEntity.status(HttpStatus.UNAUTHORIZED).headers(headers).body(ApiResponse.error("Unauthorized"));
    }

    // Security: access denied (403)
    @ExceptionHandler(AccessDeniedException.class)
    public ResponseEntity<ApiResponse<?>> handleAccessDenied(AccessDeniedException ex) {
        log.warn("Access denied: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.FORBIDDEN).body(ApiResponse.error("Access denied"));
    }

    // Not found translations (NoSuchElementException often used)
    @ExceptionHandler(NoSuchElementException.class)
    public ResponseEntity<ApiResponse<?>> handleNotFound(NoSuchElementException ex) {
        log.info("Not found: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(ApiResponse.error("Resource not found"));
    }

    // Generic IllegalArgument -> 400
    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<ApiResponse<?>> handleIllegalArgument(IllegalArgumentException ex) {
        log.info("Bad request: {}", ex.getMessage());
        return ResponseEntity.badRequest().body(ApiResponse.error(ex.getMessage()));
    }

    // Fallback - don't leak internals; return safe generic error
    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiResponse<?>> handleAll(Exception ex) {
        // log stack trace on server side for diagnostics
        log.error("Unhandled exception: {}", ex.getMessage(), ex);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(ApiResponse.error("Internal server error"));
    }

}

package org.example.userservice.services;

import jakarta.transaction.Transactional;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.example.userservice.dto.*;
import org.example.userservice.entities.User;
import org.example.userservice.exceptions.CustomException;
import org.example.userservice.jwt.RefreshTokenService;
import org.example.userservice.mappers.UserMapper;
import org.example.userservice.repositories.UserRepository;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.util.UUID;

@Service
@RequiredArgsConstructor
@Slf4j
public class UserService {

    private final UserRepository userRepository;
    private final UserMapper userMapper;
    private final PasswordEncoder passwordEncoder;
    private final RefreshTokenService refreshTokenService;

    @Transactional
    public void createUser(UserRequest user) {
        if(userRepository.existsByEmail(user.email())) {
            throw new DataIntegrityViolationException("Email already exists");
        }
        User newUser = userMapper.toUser(user);
        newUser.setPassword(passwordEncoder.encode(user.password()));
        userRepository.save(newUser);
    }

    @Transactional
    public void delete(UUID id) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new CustomException("User not found", HttpStatus.NOT_FOUND));
        refreshTokenService.revokeAllTokensForUser(user);
        userRepository.delete(user);
    }

    public UserResponse findById(UUID id) {
        return userRepository.findById(id)
                .map(userMapper::fromUser)
                .orElseThrow(() -> new CustomException("User not found", HttpStatus.NOT_FOUND));
    }

    public Page<UserResponse> findAllPaginated(Pageable pageable) {
        Page<User> page = userRepository.findAll(pageable);
        return page.map(userMapper::fromUser);
    }

    @Transactional
    public void update(UUID id, UserRequest request) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new CustomException("User not found", HttpStatus.NOT_FOUND));

        // Only check email availability if the new email is different from the current one
        if (request.email() != null && !request.email().isBlank() && !user.getEmail().equals(request.email())) {
            if (userRepository.existsByEmail(request.email())) {
                throw new DataIntegrityViolationException("Email already in use");
            }
            user.setEmail(request.email());
        }

        if (request.firstname() != null && !request.firstname().isBlank()) user.setFirstname(request.firstname());
        if (request.lastname() != null && !request.lastname().isBlank()) user.setLastname(request.lastname());
        if (request.password() != null && !request.password().isBlank()) {
            user.setPassword(passwordEncoder.encode(request.password()));
        }

        userRepository.save(user);
    }

    public UserResponse findByEmail(String email) {
        return userRepository.findByEmail(email)
                .map(userMapper::fromUser)
                .orElseThrow(() -> new CustomException("User not found", HttpStatus.NOT_FOUND));
    }
}

package org.example.userservice.services;

import jakarta.transaction.Transactional;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.example.userservice.dto.*;
import org.example.userservice.entities.User;
import org.example.userservice.jwt.RefreshTokenService;
import org.example.userservice.mappers.UserMapper;
import org.example.userservice.repositories.UserRepository;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.util.NoSuchElementException;
import java.util.UUID;

@Service
@RequiredArgsConstructor
@Slf4j
public class UserService {

    private final UserRepository userRepository;
    private final UserMapper userMapper;
    private final PasswordEncoder passwordEncoder;
    private final RefreshTokenService refreshTokenService;

    @Transactional
    public void createUser(UserRequest user) {
        if(userRepository.existsByEmail(user.email())) {
            throw new DataIntegrityViolationException("Email already exists");
        }
        User newUser = userMapper.toUser(user);
        newUser.setPassword(passwordEncoder.encode(user.password()));
        userRepository.save(newUser);
    }

    @Transactional
    public void delete(UUID id) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new NoSuchElementException("User not found"));
        refreshTokenService.revokeAllTokensForUser(user);
        userRepository.delete(user);
    }

    public UserResponse findById(UUID id) {
        return userRepository.findById(id)
                .map(userMapper::fromUser)
                .orElseThrow(() -> new NoSuchElementException("User not found"));
    }

    public Page<UserResponse> findAllPaginated(Pageable pageable) {
        Page<User> page = userRepository.findAll(pageable);
        return page.map(userMapper::fromUser);
    }

    @Transactional
    public void update(UUID id, UserRequest request) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new NoSuchElementException("User not found"));

        // Only check email availability if the new email is different from the current one
        if (request.email() != null && !request.email().isBlank() && !user.getEmail().equals(request.email())) {
            if (userRepository.existsByEmail(request.email())) {
                throw new DataIntegrityViolationException("Email already in use");
            }
            user.setEmail(request.email());
        }

        if (request.firstname() != null && !request.firstname().isBlank()) user.setFirstname(request.firstname());
        if (request.lastname() != null && !request.lastname().isBlank()) user.setLastname(request.lastname());
        if (request.password() != null && !request.password().isBlank()) {
            user.setPassword(passwordEncoder.encode(request.password()));
        }

        userRepository.save(user);
    }

    public UserResponse findByEmail(String email) {
        return userRepository.findByEmail(email)
                .map(userMapper::fromUser)
                .orElseThrow(() -> new NoSuchElementException("User not found"));
    }
}

package org.example.userservice.service;

import org.example.userservice.dto.UserRequest;
import org.example.userservice.dto.UserResponse;
import org.example.userservice.entities.User;
import org.example.userservice.enums.Role;
import org.example.userservice.exceptions.CustomException;
import org.example.userservice.jwt.RefreshTokenService;
import org.example.userservice.mappers.UserMapper;
import org.example.userservice.repositories.UserRepository;
import org.example.userservice.services.UserService;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageImpl;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.security.crypto.password.PasswordEncoder;

import java.util.List;
import java.util.Optional;
import java.util.UUID;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
@DisplayName("UserService Unit Tests")
class UserServiceTest {

    @Mock
    private UserRepository userRepository;

    @Mock
    private UserMapper userMapper;

    @Mock
    private PasswordEncoder passwordEncoder;

    @Mock
    private RefreshTokenService refreshTokenService;

    @InjectMocks
    private UserService userService;


    private User buildUser(UUID id) {
        return User.builder()
                .firstname("John")
                .lastname("Doe")
                .email("john@example.com")
                .password("encoded-password")
                .role(Role.USER)
                .verified(true)
                .build();
    }

    private UserResponse buildUserResponse(UUID id) {
        return new UserResponse(id, "John", "Doe", "john@example.com");
    }

    /**
     * Full update request — all fields populated and valid.
     */
    private UserRequest fullRequest(String firstname, String lastname, String email, String password) {
        return new UserRequest(firstname, lastname, email, password);
    }

    // -----------------------------------------------------------------------
    // createUser()
    //
    // Rules:
    //   1. Throws DataIntegrityViolationException when email already exists
    //   2. Maps request to User entity via userMapper
    //   3. Encodes the raw password before persisting — never stores plaintext
    //   4. Saves the new user
    //   5. Does NOT save when email is duplicate — repository never called
    //
    // ⚠️  Design note: createUser() throws DataIntegrityViolationException
    //     (a Spring framework exception) while update() throws CustomException
    //     for the same duplicate-email scenario. This inconsistency means the
    //     global @ExceptionHandler(CustomException.class) won't catch it and
    //     the client receives a 500 instead of a meaningful 409 CONFLICT.
    //     Recommended fix: replace with
    //     throw new CustomException("Email already exists", HttpStatus.CONFLICT);
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("createUser()")
    class CreateUser {

        @Test
        @DisplayName("should map, encode password, and save new user when email is available")
        void shouldCreateUserSuccessfully() {
            UserRequest request = fullRequest("John", "Doe", "john@example.com", "RawPass1!");
            User mappedUser = buildUser(null);

            when(userRepository.existsByEmail("john@example.com")).thenReturn(false);
            when(userMapper.toUser(request)).thenReturn(mappedUser);
            when(passwordEncoder.encode("RawPass1!")).thenReturn("encoded-password");

            userService.createUser(request);

            // Verify password was encoded before save — plaintext must never reach the DB
            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            assertThat(captor.getValue().getPassword()).isEqualTo("encoded-password");
        }

        @Test
        @DisplayName("should encode password onto the mapped entity — not the original request value")
        void shouldSetEncodedPasswordOnMappedEntity() {
            UserRequest request = fullRequest("John", "Doe", "john@example.com", "RawPass1!");
            User mappedUser = buildUser(null); // mapper returns entity with raw password initially

            when(userRepository.existsByEmail("john@example.com")).thenReturn(false);
            when(userMapper.toUser(request)).thenReturn(mappedUser);
            when(passwordEncoder.encode("RawPass1!")).thenReturn("hashed-value");

            userService.createUser(request);

            // The entity saved must carry the encoded value, not whatever toUser() set
            verify(passwordEncoder).encode("RawPass1!");
            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            assertThat(captor.getValue().getPassword()).isEqualTo("hashed-value");
        }

        @Test
        @DisplayName("should throw DataIntegrityViolationException when email already exists")
        void shouldThrowWhenEmailAlreadyExists() {
            UserRequest request = fullRequest("John", "Doe", "john@example.com", "RawPass1!");
            when(userRepository.existsByEmail("john@example.com")).thenReturn(true);

            // ⚠️ Currently throws DataIntegrityViolationException — see design note above.
            // Once fixed to CustomException(CONFLICT), update this assertion accordingly.
            assertThatThrownBy(() -> userService.createUser(request))
                    .isInstanceOf(DataIntegrityViolationException.class)
                    .hasMessage("Email already exists");

            // mapper and repository.save must never be reached
            verifyNoInteractions(userMapper);
            verify(userRepository, never()).save(any());
        }

        @Test
        @DisplayName("should not interact with mapper or save when email is duplicate")
        void shouldAbortEarlyOnDuplicateEmail() {
            UserRequest request = fullRequest("John", "Doe", "duplicate@example.com", "RawPass1!");
            when(userRepository.existsByEmail("duplicate@example.com")).thenReturn(true);

            assertThatThrownBy(() -> userService.createUser(request))
                    .isInstanceOf(DataIntegrityViolationException.class)
                    .hasMessage("Email already exists")
                    .extracting(e -> ((CustomException) e).getStatus())
                    .isEqualTo(HttpStatus.CONFLICT);

            verifyNoInteractions(userMapper);
            verifyNoInteractions(passwordEncoder);
            verify(userRepository, never()).save(any());
        }
    }

    // -----------------------------------------------------------------------
    // delete()
    //
    // Rules:
    //   1. Finds user by id — throws NOT_FOUND if missing
    //   2. Revokes all refresh tokens before deletion
    //   3. Deletes the user
    //   4. Token revocation happens BEFORE deletion (order matters for FK integrity)
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("delete()")
    class Delete {

        @Test
        @DisplayName("should revoke all tokens then delete user when found")
        void shouldRevokeTokensThenDeleteUser() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            userService.delete(id);

            // Verify order: revoke THEN delete — FK integrity depends on this
            var inOrder = inOrder(refreshTokenService, userRepository);
            inOrder.verify(refreshTokenService).revokeAllTokensForUser(user);
            inOrder.verify(userRepository).delete(user);
        }

        @Test
        @DisplayName("should throw NOT_FOUND when user does not exist")
        void shouldThrowNotFoundWhenUserMissing() {
            UUID id = UUID.randomUUID();
            when(userRepository.findById(id)).thenReturn(Optional.empty());

            assertThatThrownBy(() -> userService.delete(id))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("User not found")
                    .extracting(e -> ((CustomException) e).getStatus())
                    .isEqualTo(HttpStatus.NOT_FOUND);

            // Neither token revocation nor deletion should be attempted
            verifyNoInteractions(refreshTokenService);
            verify(userRepository, never()).delete(any());
        }
    }

    // -----------------------------------------------------------------------
    // findById()
    //
    // Rules:
    //   1. Returns mapped UserResponse when user exists
    //   2. Throws NOT_FOUND when user missing
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("findById()")
    class FindById {

        @Test
        @DisplayName("should return mapped UserResponse when user exists")
        void shouldReturnMappedResponseWhenUserExists() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            UserResponse expected = buildUserResponse(id);

            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            when(userMapper.fromUser(user)).thenReturn(expected);

            UserResponse result = userService.findById(id);

            assertThat(result).isEqualTo(expected);
            verify(userMapper).fromUser(user);
        }

        @Test
        @DisplayName("should throw NOT_FOUND when user does not exist")
        void shouldThrowNotFoundWhenUserMissing() {
            UUID id = UUID.randomUUID();
            when(userRepository.findById(id)).thenReturn(Optional.empty());

            assertThatThrownBy(() -> userService.findById(id))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("User not found")
                    .extracting(e -> ((CustomException) e).getStatus())
                    .isEqualTo(HttpStatus.NOT_FOUND);

            verifyNoInteractions(userMapper);
        }
    }

    // -----------------------------------------------------------------------
    // findAllPaginated()
    //
    // Rules:
    //   1. Delegates to repository with the given Pageable
    //   2. Maps every User in the page to UserResponse via userMapper
    //   3. Returns an empty page correctly (no NPE, no mapper calls)
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("findAllPaginated()")
    class FindAllPaginated {

        @Test
        @DisplayName("should return page of mapped UserResponse")
        void shouldReturnPageOfMappedResponses() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            UserResponse response = buildUserResponse(id);
            Pageable pageable = PageRequest.of(0, 10);
            Page<User> userPage = new PageImpl<>(List.of(user), pageable, 1);

            when(userRepository.findAll(pageable)).thenReturn(userPage);
            when(userMapper.fromUser(user)).thenReturn(response);

            Page<UserResponse> result = userService.findAllPaginated(pageable);

            assertThat(result.getContent()).containsExactly(response);
            assertThat(result.getTotalElements()).isEqualTo(1);
        }

        @Test
        @DisplayName("should return empty page when no users exist")
        void shouldReturnEmptyPageWhenNoUsers() {
            Pageable pageable = PageRequest.of(0, 10);
            when(userRepository.findAll(pageable)).thenReturn(Page.empty(pageable));

            Page<UserResponse> result = userService.findAllPaginated(pageable);

            assertThat(result.getContent()).isEmpty();
            verifyNoInteractions(userMapper); // mapper must not be called on empty page
        }
    }

    // -----------------------------------------------------------------------
    // findByEmail()
    //
    // Rules:
    //   1. Returns mapped UserResponse when user exists
    //   2. Throws NOT_FOUND when user missing
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("findByEmail()")
    class FindByEmail {

        @Test
        @DisplayName("should return mapped UserResponse when email exists")
        void shouldReturnMappedResponseWhenEmailExists() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            UserResponse expected = buildUserResponse(id);

            when(userRepository.findByEmail("john@example.com")).thenReturn(Optional.of(user));
            when(userMapper.fromUser(user)).thenReturn(expected);

            UserResponse result = userService.findByEmail("john@example.com");

            assertThat(result).isEqualTo(expected);
        }

        @Test
        @DisplayName("should throw NOT_FOUND when email does not exist")
        void shouldThrowNotFoundWhenEmailMissing() {
            when(userRepository.findByEmail("ghost@example.com")).thenReturn(Optional.empty());

            assertThatThrownBy(() -> userService.findByEmail("ghost@example.com"))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("User not found")
                    .extracting(e -> ((CustomException) e).getStatus())
                    .isEqualTo(HttpStatus.NOT_FOUND);
        }
    }

    // -----------------------------------------------------------------------
    // update()
    //
    // This is the most logic-dense method — every branch must be covered.
    //
    // Rules:
    //   1. Throws NOT_FOUND when user missing
    //   2. Updates firstname only when non-null and non-blank
    //   3. Updates lastname only when non-null and non-blank
    //   4. Updates email only when different from current AND not already taken
    //   5. Throws UNPROCESSABLE_ENTITY when new email is already taken by another user
    //   6. Does NOT update email when new value equals current value
    //   7. Encodes password when provided
    //   8. Does NOT touch password when field is null or blank
    //   9. Saves the user after all mutations
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("update()")
    class Update {

        @Test
        @DisplayName("should throw NOT_FOUND when user does not exist")
        void shouldThrowNotFoundWhenUserMissing() {
            UUID id = UUID.randomUUID();
            when(userRepository.findById(id)).thenReturn(Optional.empty());

            assertThatThrownBy(() -> userService.update(id,
                    fullRequest("Jane", "Smith", "jane@example.com", "NewPass1!")))
                    .isInstanceOf(CustomException.class)
                    .hasMessage("User not found")
                    .extracting(e -> ((CustomException) e).getStatus())
                    .isEqualTo(HttpStatus.NOT_FOUND);

            verify(userRepository, never()).save(any());
        }

        @Test
        @DisplayName("should update firstname and lastname when valid")
        void shouldUpdateFirstnameAndLastname() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            // same email — no conflict check triggered
            when(userRepository.existsByEmail(any())).thenReturn(false);

            userService.update(id, fullRequest("Jane", "Smith", "john@example.com", "NewPass1!"));

            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            User saved = captor.getValue();

            assertThat(saved.getFirstname()).isEqualTo("Jane");
            assertThat(saved.getLastname()).isEqualTo("Smith");
        }

        @Test
        @DisplayName("should update email when new email is different and not taken")
        void shouldUpdateEmailWhenDifferentAndAvailable() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id); // current email: john@example.com
            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            when(userRepository.existsByEmail("newemail@example.com")).thenReturn(false);

            userService.update(id, fullRequest("John", "Doe", "newemail@example.com", "NewPass1!"));

            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());

            assertThat(captor.getValue().getEmail()).isEqualTo("newemail@example.com");
        }

        @Test
        @DisplayName("should throw UNPROCESSABLE_ENTITY when new email is already taken")
        void shouldThrowWhenEmailAlreadyTaken() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id); // current: john@example.com
            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            when(userRepository.existsByEmail("taken@example.com")).thenReturn(true);

            assertThatThrownBy(() -> userService.update(id,
                    fullRequest("John", "Doe", "taken@example.com", "NewPass1!")))
                    .isInstanceOf(DataIntegrityViolationException.class)
                    .hasMessage("Email already in use")
                    .extracting(e -> ((DataIntegrityViolationException) e).ge)
                    .isEqualTo(HttpStatus.CONFLICT);

            verify(userRepository, never()).save(any());
        }

        @Test
        @DisplayName("should NOT check email availability when new email equals current email")
        void shouldNotCheckEmailAvailabilityWhenEmailUnchanged() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id); // current: john@example.com
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            // same email as current — existsByEmail must never be called
            userService.update(id, fullRequest("John", "Doe", "john@example.com", "NewPass1!"));

            verify(userRepository, never()).existsByEmail(any());
            verify(userRepository).save(any());
        }

        @Test
        @DisplayName("should encode and update password when provided")
        void shouldEncodeAndUpdatePassword() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            when(passwordEncoder.encode("NewPass1!")).thenReturn("hashed-new-password");

            userService.update(id, fullRequest("John", "Doe", "john@example.com", "NewPass1!"));

            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            verify(passwordEncoder).encode("NewPass1!");

            assertThat(captor.getValue().getPassword()).isEqualTo("hashed-new-password");
        }

        @Test
        @DisplayName("should NOT update password when password field is null")
        void shouldNotUpdatePasswordWhenNull() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            // UserRequest with null password — simulates partial update intent
            userService.update(id, new UserRequest("John", "Doe", "john@example.com", null));

            verifyNoInteractions(passwordEncoder);

            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            assertThat(captor.getValue().getPassword()).isEqualTo("encoded-password"); // unchanged
        }

        @Test
        @DisplayName("should NOT update password when password field is blank")
        void shouldNotUpdatePasswordWhenBlank() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            userService.update(id, new UserRequest("John", "Doe", "john@example.com", "   "));

            verifyNoInteractions(passwordEncoder);
        }

        @Test
        @DisplayName("should always save user after any valid update")
        void shouldAlwaysSaveAfterUpdate() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            userService.update(id, fullRequest("John", "Doe", "john@example.com", "NewPass1!"));

            verify(userRepository, times(1)).save(user);
        }
    }
}

package org.example.userservice.service;

import org.example.userservice.dto.UserRequest;
import org.example.userservice.dto.UserResponse;
import org.example.userservice.entities.User;
import org.example.userservice.enums.Role;
import org.example.userservice.jwt.RefreshTokenService;
import org.example.userservice.mappers.UserMapper;
import org.example.userservice.repositories.UserRepository;
import org.example.userservice.services.UserService;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageImpl;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.security.crypto.password.PasswordEncoder;

import java.util.List;
import java.util.NoSuchElementException;
import java.util.Optional;
import java.util.UUID;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
@DisplayName("UserService Unit Tests")
class UserServiceTest {

    @Mock
    private UserRepository userRepository;

    @Mock
    private UserMapper userMapper;

    @Mock
    private PasswordEncoder passwordEncoder;

    @Mock
    private RefreshTokenService refreshTokenService;

    @InjectMocks
    private UserService userService;


    private User buildUser(UUID id) {
        return User.builder()
                .firstname("John")
                .lastname("Doe")
                .email("john@example.com")
                .password("encoded-password")
                .role(Role.USER)
                .verified(true)
                .build();
    }

    private UserResponse buildUserResponse(UUID id) {
        return new UserResponse(id, "John", "Doe", "john@example.com");
    }

    /**
     * Full update request — all fields populated and valid.
     */
    private UserRequest fullRequest(String firstname, String lastname, String email, String password) {
        return new UserRequest(firstname, lastname, email, password);
    }

    // -----------------------------------------------------------------------
    // createUser()
    //
    // Rules:
    //   1. Throws DataIntegrityViolationException when email already exists
    //   2. Maps request to User entity via userMapper
    //   3. Encodes the raw password before persisting — never stores plaintext
    //   4. Saves the new user
    //   5. Does NOT save when email is duplicate — repository never called
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("createUser()")
    class CreateUser {

        @Test
        @DisplayName("should map, encode password, and save new user when email is available")
        void shouldCreateUserSuccessfully() {
            UserRequest request = fullRequest("John", "Doe", "john@example.com", "RawPass1!");
            User mappedUser = buildUser(null);

            when(userRepository.existsByEmail("john@example.com")).thenReturn(false);
            when(userMapper.toUser(request)).thenReturn(mappedUser);
            when(passwordEncoder.encode("RawPass1!")).thenReturn("encoded-password");

            userService.createUser(request);

            // Verify password was encoded before save — plaintext must never reach the DB
            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            assertThat(captor.getValue().getPassword()).isEqualTo("encoded-password");
        }

        @Test
        @DisplayName("should encode password onto the mapped entity — not the original request value")
        void shouldSetEncodedPasswordOnMappedEntity() {
            UserRequest request = fullRequest("John", "Doe", "john@example.com", "RawPass1!");
            User mappedUser = buildUser(null); // mapper returns entity with raw password initially

            when(userRepository.existsByEmail("john@example.com")).thenReturn(false);
            when(userMapper.toUser(request)).thenReturn(mappedUser);
            when(passwordEncoder.encode("RawPass1!")).thenReturn("hashed-value");

            userService.createUser(request);

            // The entity saved must carry the encoded value, not whatever toUser() set
            verify(passwordEncoder).encode("RawPass1!");
            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            assertThat(captor.getValue().getPassword()).isEqualTo("hashed-value");
        }

        @Test
        @DisplayName("should throw DataIntegrityViolationException when email already exists")
        void shouldThrowWhenEmailAlreadyExists() {
            UserRequest request = fullRequest("John", "Doe", "john@example.com", "RawPass1!");
            when(userRepository.existsByEmail("john@example.com")).thenReturn(true);

            assertThatThrownBy(() -> userService.createUser(request))
                    .isInstanceOf(DataIntegrityViolationException.class)
                    .hasMessage("Email already exists");

            // mapper and repository.save must never be reached
            verifyNoInteractions(userMapper);
            verify(userRepository, never()).save(any());
        }

        @Test
        @DisplayName("should not interact with mapper or save when email is duplicate")
        void shouldAbortEarlyOnDuplicateEmail() {
            UserRequest request = fullRequest("John", "Doe", "duplicate@example.com", "RawPass1!");
            when(userRepository.existsByEmail("duplicate@example.com")).thenReturn(true);

            assertThatThrownBy(() -> userService.createUser(request))
                    .isInstanceOf(DataIntegrityViolationException.class)
                    .hasMessage("Email already exists");

            verifyNoInteractions(userMapper);
            verifyNoInteractions(passwordEncoder);
            verify(userRepository, never()).save(any());
        }
    }

    // -----------------------------------------------------------------------
    // delete()
    //
    // Rules:
    //   1. Finds user by id — throws NOT_FOUND if missing
    //   2. Revokes all refresh tokens before deletion
    //   3. Deletes the user
    //   4. Token revocation happens BEFORE deletion (order matters for FK integrity)
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("delete()")
    class Delete {

        @Test
        @DisplayName("should revoke all tokens then delete user when found")
        void shouldRevokeTokensThenDeleteUser() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            userService.delete(id);

            // Verify order: revoke THEN delete — FK integrity depends on this
            var inOrder = inOrder(refreshTokenService, userRepository);
            inOrder.verify(refreshTokenService).revokeAllTokensForUser(user);
            inOrder.verify(userRepository).delete(user);
        }

        @Test
        @DisplayName("should throw NOT_FOUND when user does not exist")
        void shouldThrowNotFoundWhenUserMissing() {
            UUID id = UUID.randomUUID();
            when(userRepository.findById(id)).thenReturn(Optional.empty());

            assertThatThrownBy(() -> userService.delete(id))
                    .isInstanceOf(NoSuchElementException.class)
                    .hasMessage("User not found");

            // Neither token revocation nor deletion should be attempted
            verifyNoInteractions(refreshTokenService);
            verify(userRepository, never()).delete(any());
        }
    }

    // -----------------------------------------------------------------------
    // findById()
    //
    // Rules:
    //   1. Returns mapped UserResponse when user exists
    //   2. Throws NOT_FOUND when user missing
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("findById()")
    class FindById {

        @Test
        @DisplayName("should return mapped UserResponse when user exists")
        void shouldReturnMappedResponseWhenUserExists() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            UserResponse expected = buildUserResponse(id);

            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            when(userMapper.fromUser(user)).thenReturn(expected);

            UserResponse result = userService.findById(id);

            assertThat(result).isEqualTo(expected);
            verify(userMapper).fromUser(user);
        }

        @Test
        @DisplayName("should throw NOT_FOUND when user does not exist")
        void shouldThrowNotFoundWhenUserMissing() {
            UUID id = UUID.randomUUID();
            when(userRepository.findById(id)).thenReturn(Optional.empty());

            assertThatThrownBy(() -> userService.findById(id))
                    .isInstanceOf(NoSuchElementException.class)
                    .hasMessage("User not found");

            verifyNoInteractions(userMapper);
        }
    }

    // -----------------------------------------------------------------------
    // findAllPaginated()
    //
    // Rules:
    //   1. Delegates to repository with the given Pageable
    //   2. Maps every User in the page to UserResponse via userMapper
    //   3. Returns an empty page correctly (no NPE, no mapper calls)
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("findAllPaginated()")
    class FindAllPaginated {

        @Test
        @DisplayName("should return page of mapped UserResponse")
        void shouldReturnPageOfMappedResponses() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            UserResponse response = buildUserResponse(id);
            Pageable pageable = PageRequest.of(0, 10);
            Page<User> userPage = new PageImpl<>(List.of(user), pageable, 1);

            when(userRepository.findAll(pageable)).thenReturn(userPage);
            when(userMapper.fromUser(user)).thenReturn(response);

            Page<UserResponse> result = userService.findAllPaginated(pageable);

            assertThat(result.getContent()).containsExactly(response);
            assertThat(result.getTotalElements()).isEqualTo(1);
        }

        @Test
        @DisplayName("should return empty page when no users exist")
        void shouldReturnEmptyPageWhenNoUsers() {
            Pageable pageable = PageRequest.of(0, 10);
            when(userRepository.findAll(pageable)).thenReturn(Page.empty(pageable));

            Page<UserResponse> result = userService.findAllPaginated(pageable);

            assertThat(result.getContent()).isEmpty();
            verifyNoInteractions(userMapper); // mapper must not be called on empty page
        }
    }

    // -----------------------------------------------------------------------
    // findByEmail()
    //
    // Rules:
    //   1. Returns mapped UserResponse when user exists
    //   2. Throws NOT_FOUND when user missing
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("findByEmail()")
    class FindByEmail {

        @Test
        @DisplayName("should return mapped UserResponse when email exists")
        void shouldReturnMappedResponseWhenEmailExists() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            UserResponse expected = buildUserResponse(id);

            when(userRepository.findByEmail("john@example.com")).thenReturn(Optional.of(user));
            when(userMapper.fromUser(user)).thenReturn(expected);

            UserResponse result = userService.findByEmail("john@example.com");

            assertThat(result).isEqualTo(expected);
        }

        @Test
        @DisplayName("should throw NOT_FOUND when email does not exist")
        void shouldThrowNotFoundWhenEmailMissing() {
            when(userRepository.findByEmail("ghost@example.com")).thenReturn(Optional.empty());

            assertThatThrownBy(() -> userService.findByEmail("ghost@example.com"))
                    .isInstanceOf(NoSuchElementException.class)
                    .hasMessage("User not found");
        }
    }

    // -----------------------------------------------------------------------
    // update()
    //
    // This is the most logic-dense method — every branch must be covered.
    //
    // Rules:
    //   1. Throws NOT_FOUND when user missing
    //   2. Updates firstname only when non-null and non-blank
    //   3. Updates lastname only when non-null and non-blank
    //   4. Updates email only when different from current AND not already taken
    //   5. Throws UNPROCESSABLE_ENTITY when new email is already taken by another user
    //   6. Does NOT update email when new value equals current value
    //   7. Encodes password when provided
    //   8. Does NOT touch password when field is null or blank
    //   9. Saves the user after all mutations
    // -----------------------------------------------------------------------

    @Nested
    @DisplayName("update()")
    class Update {

        @Test
        @DisplayName("should throw NOT_FOUND when user does not exist")
        void shouldThrowNotFoundWhenUserMissing() {
            UUID id = UUID.randomUUID();
            when(userRepository.findById(id)).thenReturn(Optional.empty());

            assertThatThrownBy(() -> userService.update(id,
                    fullRequest("Jane", "Smith", "jane@example.com", "NewPass1!")))
                    .isInstanceOf(NoSuchElementException.class)
                    .hasMessage("User not found");

            verify(userRepository, never()).save(any());
        }

        @Test
        @DisplayName("should update firstname and lastname when valid")
        void shouldUpdateFirstnameAndLastname() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            userService.update(id, fullRequest("Jane", "Smith", "john@example.com", "NewPass1!"));

            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            User saved = captor.getValue();

            assertThat(saved.getFirstname()).isEqualTo("Jane");
            assertThat(saved.getLastname()).isEqualTo("Smith");
        }

        @Test
        @DisplayName("should update email when new email is different and not taken")
        void shouldUpdateEmailWhenDifferentAndAvailable() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id); // current email: john@example.com
            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            when(userRepository.existsByEmail("newemail@example.com")).thenReturn(false);

            userService.update(id, fullRequest("John", "Doe", "newemail@example.com", "NewPass1!"));

            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());

            assertThat(captor.getValue().getEmail()).isEqualTo("newemail@example.com");
        }

        @Test
        @DisplayName("should throw UNPROCESSABLE_ENTITY when new email is already taken")
        void shouldThrowWhenEmailAlreadyTaken() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id); // current: john@example.com
            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            when(userRepository.existsByEmail("taken@example.com")).thenReturn(true);

            assertThatThrownBy(() -> userService.update(id,
                    fullRequest("John", "Doe", "taken@example.com", "NewPass1!")))
                    .isInstanceOf(DataIntegrityViolationException.class)
                    .hasMessage("Email already in use");

            verify(userRepository, never()).save(any());
        }

        @Test
        @DisplayName("should NOT check email availability when new email equals current email")
        void shouldNotCheckEmailAvailabilityWhenEmailUnchanged() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id); // current: john@example.com
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            // same email as current — existsByEmail must never be called
            userService.update(id, fullRequest("John", "Doe", "john@example.com", "NewPass1!"));

            verify(userRepository, never()).existsByEmail(any());
            verify(userRepository).save(any());
        }

        @Test
        @DisplayName("should encode and update password when provided")
        void shouldEncodeAndUpdatePassword() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));
            when(passwordEncoder.encode("NewPass1!")).thenReturn("hashed-new-password");

            userService.update(id, fullRequest("John", "Doe", "john@example.com", "NewPass1!"));

            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            verify(passwordEncoder).encode("NewPass1!");

            assertThat(captor.getValue().getPassword()).isEqualTo("hashed-new-password");
        }

        @Test
        @DisplayName("should NOT update password when password field is null")
        void shouldNotUpdatePasswordWhenNull() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            // UserRequest with null password — simulates partial update intent
            userService.update(id, new UserRequest("John", "Doe", "john@example.com", null));

            verifyNoInteractions(passwordEncoder);

            ArgumentCaptor<User> captor = ArgumentCaptor.forClass(User.class);
            verify(userRepository).save(captor.capture());
            assertThat(captor.getValue().getPassword()).isEqualTo("encoded-password"); // unchanged
        }

        @Test
        @DisplayName("should NOT update password when password field is blank")
        void shouldNotUpdatePasswordWhenBlank() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            userService.update(id, new UserRequest("John", "Doe", "john@example.com", "   "));

            verifyNoInteractions(passwordEncoder);
        }

        @Test
        @DisplayName("should always save user after any valid update")
        void shouldAlwaysSaveAfterUpdate() {
            UUID id = UUID.randomUUID();
            User user = buildUser(id);
            when(userRepository.findById(id)).thenReturn(Optional.of(user));

            userService.update(id, fullRequest("John", "Doe", "john@example.com", "NewPass1!"));

            verify(userRepository, times(1)).save(user);
        }
    }
}
